//#region src/lib/components/Autosuggest/createAccessibilityProps.ts
const getItemId = (id, index) => `${id}-item-${index}`;
const createAccessibilityProps = ({ id, highlightedIndex, isOpen }) => {
	const menuId = `${id}-menu`;
	const assistiveDescriptionId = `${id}-aria-description`;
	return {
		inputProps: {
			id,
			role: "combobox",
			"aria-haspopup": "listbox",
			"aria-owns": isOpen ? menuId : void 0,
			"aria-controls": menuId,
			"aria-expanded": isOpen,
			"aria-autocomplete": "list",
			"aria-activedescendant": typeof highlightedIndex === "number" ? getItemId(id, highlightedIndex) : void 0,
			"aria-describedby": assistiveDescriptionId,
			autoComplete: "off",
			spellCheck: false
		},
		assistiveDescriptionProps: { id: assistiveDescriptionId },
		menuProps: {
			id: menuId,
			role: "listbox"
		},
		getItemProps: ({ index, label, description, groupHeading }) => ({
			id: getItemId(id, index),
			role: "option",
			"aria-selected": index === highlightedIndex,
			"aria-label": `${label}${description ? ` - ${description}` : ""}${groupHeading ? ` (${groupHeading})` : ""}`
		})
	};
};
//#endregion
export { createAccessibilityProps, getItemId };
