//#region src/lib/utils/optimizeResponsiveArray.ts
const optimizeResponsiveArray = (value) => {
	let lastValue;
	const values = value.map((v) => {
		if (v !== lastValue && v !== null) {
			lastValue = v;
			return v;
		}
		return null;
	});
	return [
		values[0] ?? null,
		values[1] ?? null,
		values[2] ?? null,
		values[3] ?? null
	];
};
//#endregion
export { optimizeResponsiveArray };
